from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Group triples by subject to find the main entity
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the subject with most triples (main entity)
    main_subject = max(subject_triples.keys(), key=lambda k: len(subject_triples[k]))
    main_triples = subject_triples[main_subject]

    # Build sentence parts efficiently
    parts = []
    has_born = False
    has_died = False

    for t in main_triples:
        obj = t.object
        pred = t.predicate

        if pred == "birthPlace":
            parts.append(f"born in {obj}")
            has_born = True
        elif pred == "birthDate":
            parts.append(f"born on {obj}")
            has_born = True
        elif pred == "birthYear":
            parts.append(f"born in {obj}")
            has_born = True
        elif pred == "deathPlace":
            parts.append(f"died in {obj}")
            has_died = True
        elif pred == "deathDate":
            parts.append(f"died on {obj}")
            has_died = True
        elif pred == "deathYear":
            parts.append(f"died in {obj}")
            has_died = True
        elif pred == "nationality":
            parts.append(f"{obj} national")
        elif pred == "party":
            parts.append(f"member of {obj}")
        elif pred == "office":
            parts.append(f"held the office of {obj}")
        elif pred == "successor":
            parts.append(f"succeeded by {obj}")
        elif pred == "predecessor":
            parts.append(f"preceded by {obj}")
        elif pred == "spouse":
            parts.append(f"married to {obj}")
        elif pred == "residence":
            parts.append(f"resides at {obj}")
        elif pred == "region":
            parts.append(f"from {obj}")
        elif pred == "country":
            parts.append(f"from {obj}")
        elif pred == "capital":
            parts.append(f"capital is {obj}")
        elif pred == "largestCity":
            parts.append(f"largest city is {obj}")
        elif pred == "currency":
            parts.append(f"uses {obj}")
        elif pred == "language":
            parts.append(f"speaks {obj}")
        elif pred == "officialLanguage":
            parts.append(f"official language is {obj}")
        elif pred == "leader":
            parts.append(f"led by {obj}")
        elif pred == "battle":
            parts.append(f"participated in {obj}")
        elif pred == "almaMater":
            parts.append(f"educated at {obj}")
        elif pred == "profession":
            parts.append(f"worked as {obj}")
        elif pred == "religion":
            parts.append(f"follows {obj}")
        elif pred == "militaryBranch":
            parts.append(f"of {obj}")
        elif pred == "militaryRank":
            parts.append(f"with rank of {obj}")
        elif pred == "serviceStartYear":
            parts.append(f"started service in {obj}")
        elif pred == "activeYearsStartDate":
            parts.append(f"active from {obj}")
        elif pred == "activeYearsEndDate":
            parts.append(f"active until {obj}")
        elif pred == "numberOfVotesAttained":
            parts.append(f"received {obj} votes")
        elif pred == "award":
            parts.append(f"awarded {obj}")
        elif pred == "unit":
            parts.append(f"of {obj}")
        elif pred == "hasDeputy":
            parts.append(f"with deputy {obj}")
        elif pred == "inOfficeWhileVicePresident":
            parts.append(f"during {obj}'s vice presidency")
        elif pred == "inOfficeWhilePrimeMinister":
            parts.append(f"during {obj}'s prime ministership")
        elif pred == "inOfficeWhilePresident":
            parts.append(f"during {obj}'s presidency")

    if not parts:
        return ""

    return main_subject + " " + ", ".join(parts)

